import{_ as p,o as e,c as a,j as r,a as t,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"无休盛宴","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/1.血统与训练/4.综合类/千禧骑士/武器/无休盛宴.md","filePath":"4.资源分区/1.血统与训练/4.综合类/千禧骑士/武器/无休盛宴.md"}'),s={name:"4.资源分区/1.血统与训练/4.综合类/千禧骑士/武器/无休盛宴.md"};function o(d,b,l,_,i,c){return e(),a("div",null,[...b[0]||(b[0]=[r("h1",{id:"无休盛宴",tabindex:"-1"},[t("无休盛宴 "),r("a",{class:"header-anchor",href:"#无休盛宴","aria-label":'Permalink to "无休盛宴"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"灵魂蓝调015")])])],-1),n('<h1 id="无休盛宴-1" tabindex="-1">无休盛宴 <a class="header-anchor" href="#无休盛宴-1" aria-label="Permalink to &quot;无休盛宴&quot;">​</a></h1><p>无休盛宴<br> D+500<br> 特异本质<br> 法术强度6点<br> “一钱银子买一升麦子，一钱银子买三升大麦，油和酒不可糟蹋。”无休盛宴的基础射程等同于持有者的风度*1米，攻击造成严重伤害。</p><p>这是一柄通体漆黑，其上有绿纹爬缠的天平，无论其怎么调整，总是会向其中一方偏斜。使用无休盛宴的前提为信仰【雅威】或成为千禧骑士。</p><p>无休盛宴无需主动升级，只需购买一项对应等级的无休盛宴能够使用的材料便会自动升级，同时，每个等级的材料将不会提供属性点，第一次购买时会提供标注的法术强度。<br> （例：轮回者教皇购买了【盐】，无休盛宴升级至C级，获得对应标注的法术强度，他又购买了【肉】，则因为没有提升等级，因此不获得额外的法术强度）</p><p>在此阶段下，获得有价无市、不公裁判两个特性。</p><p>有价无市：在使用无休盛宴时，需先在天平两端置放材料，由材料的重量决定天平向哪一侧偏斜，天平的其中一端也可以不置放材料，但不能两端都不置放，若如此做，则无休盛宴无法正常使用。<br> 天平倾斜中较沉一方材料的效果正常生效，较轻一侧材料的效果将不生效，而是改为获得材料等级（D2C4B6A8)*传奇风度米的射程，若处于较轻一方的材料依然可以生效，则不提供射程。<br> 更换天平两端的材料是一个迅捷动作，但每一轮只能最多更换一种材料。若无特殊说明，天平的某一端不能同时盛放多种材料。</p><p>不公裁判：每个战斗场景仅限一次，持有者可以使用一个迅捷动作令天平平衡，在接下来的这一轮中，直到自己的下个回合开始前，都可以同时享受这两种材料带来的效果，但提升的射程改为额外提升持有者风度上的附加成功*持有者的风度/米。</p><p>材料：<br> 所有材料不注明价格，均为标准价格。在使用时，比较重量并计算生效情况，若两端重量相等，则选择其中一项生效。</p><p>D级</p><p>黑麦<br> 重量：15<br> 这是一碗黑麦制成的粗饭或是一块黑麦面包，坚硬而粗劣，导致难以下咽。<br> 当黑麦作为较沉一方时，还会额外提供每轮一次，在某次攻击检定后可以至多重掷一次，但必须接受后者结果的能力。<br> 并根据天平的另一端被翘起的材料等级，用以下效果替换【有价无市】中转换成的额外射程。<br> ·D级：法术强度提升4点，额外增加风度*1米基础射程。<br> ·C级：法术强度提升4点，此次攻击改为使用意志豁免进行对抗，并承受二者差值的伤害，额外增加风度*2米射程。<br> ·B级：法术强度提升4点，此次攻击改为使用意志豁免进行对抗，并附带等同于攻击出目的剧痛点数，额外增加风度*4米射程。<br> ·A级：A级材料总是视为比黑麦更重，此时，黑麦将不因【有价无市】提供额外射程，而是提供它本来的效果。</p><p>鱼<br> 重量：3<br> 这是一块或煮或煎，或腌制好晾晒风干的鱼肉。<br> 当鱼作为较沉一方时，则生效另一侧的材料能力，而非生效鱼的能力，此时，持有者使用无休盛宴进行的施法攻击还会额外再获得【贯穿】、【连射】，并额外提升风度*米的基础射程。</p><p>C级<br> 首次获得C级材料时，法术强度提升8点。</p><p>盐<br> 重量：0<br> 特殊的，盐可以与其他材料共呈一端，与盐共存的材料将视为+5重量。<br> 这是一些晶体微黄，有杂质掺入的碎盐，虽然品质很差，但也不可或缺。<br> 当盐作为较沉的一方时，即使持有者的生命最好状态中不具有任何完好，也不会因此昏迷。战斗场景中，当持有者因某些效果而昏迷，且这一效果已不能再使其昏迷时，持有者将在下一轮开始时立即醒来。</p><p>畜肉<br> 重量：7<br> 这是一块称不上美味，但富含蛋白质和油脂的畜肉。<br> 当畜肉作为较沉的一方时，持有者可以学识+施法相关专业替代格挡所用的技能与专业进行格挡。无休盛宴上的所有法术强度会转化成在格挡时生效的等量的天生防御，持有者在战斗轮中的每轮开始时会获得1点快速医疗（12医疗点），并在生命最好状态中不具有任何完好时获得【坚韧】。</p><p>蛋<br> 重量：3<br> 这是一颗刚刚拿出的鸡蛋，攒够更多能在集市上换来一些必需品或是粮食。<br> 当蛋作为较轻的一方时，【有价无市】将不会使蛋转化为额外射程提升。每轮一次，当应对一次攻击时，若蛋是较轻的一方，则替换材料的动作变为反射动作，这是一个打断效果，正常消耗AP，并在替换蛋的那一轮额外获得B级先制。</p><p>血<br> 重量：6<br> 这是一罐在屠宰牲畜时收集而来的血液，可以用于制造食物，但贸然饮用或许会生病。<br> 当血作为较沉的一方时，持有者在使用无休盛宴进行施法攻击时还会额外再获得2点吸血，若此次攻击成功激活了这些吸血，则还会使被攻击目标获得【劣化1】。</p><p>B级<br> 首次获得B级材料时，法术强度提升7点。</p><p>奶<br> 重量：8<br> 这是一罐从大型产畜上收集而来的兽乳，可以直接饮用。<br> 当奶作为较沉的一方时，持有者在使用无休盛宴进行施法攻击时，还会将此次施法攻击转化为等同于基础射程为半径的圆形范围，使用强韧豁免进行对抗。这次攻击将还额外会对范围内所有被攻击的目标产生击退效果，每在对抗中胜出1点就将额外击退其3*另一端重量米，最多击退75米。</p><p>精麦<br> 重量：10<br> 这是一穗磨盘上遗留下来的精麦，只有丰年才有机会吃上这种称得上好吃的主食。<br> 当精麦作为较沉的一方时，另一端可以放置至多数项总重量小于10的材料，这些材料不会被【有价无市】转换为额外射程，而是同时生效它们具有的较沉效果，由精麦提供【有价无市】转换的射程。<br> 当精麦作为较轻的一方时，不会被【有价无市】转换为额外射程，此时，持有者可以使用学识+专业：施法进行格挡，持有者学识技能下属的所有专业视为至少具有1级。同时，每轮一次，持有者可以自由动作进行格挡。每轮一次，持有者可以自由动作进行一次半速移动。</p><p>骨<br> 重量：5<br> 这是几块剃掉了大部分肉的骨头，或许还能食用，但食之无味，弃之可惜。<br> 当骨作为较沉的一方时，持有者使用无休盛宴进行的施法攻击还会视为具有【余波】和【幻灭】。</p><p>A级<br> 首次获得A级材料时，法术强度提升12点，并获得1点额外的附加成功。</p><p>香料<br> 重量：1<br> 特殊的，香料可以与其他材料共呈一端，与香料共存的材料将视为+7重量。<br> 这是一小撮只有大领主和贵族才能享受的起的东方香料。<br> 当香料作为较沉的一方时，另一端可以放置多种材料至其重量小于香料所在的一方。根据两端差值结算效果：<br> ≤1：被持有者以无休盛宴进行施法攻击的目标需以意志豁免进行对抗，并在受到伤害后，承受每1点所受伤害降低2点外貌和10点声望的效果，这个效果将持续存在一场景，最多将二者降低至1。<br> 2-7：一场景一次，在一次以无休盛宴进行的施法攻击中，持有者可以改为释放两道最符合其当前利益，或其最希望出现的法术，这些法术将以最优结果进行结算。<br> 7+：持有者以无休盛宴使用的所有法术的施法范围将提升至敏感范围，其敏感范围增加一倍。</p><p>蜜<br> 重量：10<br> 这是一罐新收集而来的蜂蜜，为了它，或许会有人丧命。<br> 当蜜作为较沉的一方时，持有者每拥有3点额外生命，就获得1点额外生命。每拥有3点快速医疗，就获得1点快速医疗。每拥有3点异常点治疗，就获得1点异常点治疗。每拥有24点非快速医疗提供的医疗点，就获得8点通用医疗点。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',25)])])}const m=p(s,[["render",o]]);export{f as __pageData,m as default};
